138	  units: Unit[];
139	  sources: Source[];
140	  entities: Entity[];
141	  rawChunks?: RawChunk[];
142	  relationships?: {
143	    id?: string;
144	    from: string;
145	    relation: string;
146	    to: string;
147	    unitId?: string;
148	    sourceId?: string;
149	    confidence: number;
150	    createdAt?: string;
151	  }[];
152	}
