154	const BACKEND = BACKEND_URL;
155	
156	// Read brain state directly from the Python backend on every call. We
157	// deliberately don't cache here — brain.json lives on the same VM as the
158	// backend, the fetch is microseconds, and caching introduced a live-refresh
159	// bug after job-queue ingest where the home page would show stale Recent
160	// Knowledge until a hard reload. Force-dynamic pages already prevent route
161	// segment caching; this keeps the data layer fresh too.
162	export async function readState(): Promise<State> {
163	  try {
164	    const res = await fetch(`${BACKEND}/api/state`, { cache: "no-store" });
165	    if (!res.ok) throw new Error(`Backend ${res.status}`);
166	    return res.json();
167	  } catch {
168	    return { units: [], sources: [], entities: [], rawChunks: [] };
169	  }
170	}
171	
172	export function invalidateCache() {
173	  // No data-layer cache to bust, but we still revalidate the route segment
174	  // so any client components subscribed to it pick up the fresh render.
175	  revalidatePath("/", "layout");
176	}
177	
178	export async function clearAll(): Promise<State> {
179	  invalidateCache();
180	  return { units: [], sources: [], entities: [], rawChunks: [] };
181	}
182	
183	export async function deleteUnit(unitId: string): Promise<State> {
184	  try {
185	    await fetch(`${BACKEND}/api/units/${unitId}`, { method: "DELETE" });
186	  } catch {
187	    // best-effort
188	  }
189	  invalidateCache();
190	  return readState();
191	}
