1	import type { State, Unit } from "./store";
2	import { DEPARTMENTS, type Department, type UnitKind } from "./types";
3	
4	/*
5	 * BrainOS skill generation contract:
6	 * - Skills are compact operational memory for agents, not documentation dumps.
7	 * - Keep facts atomic, department-scoped, temporal-aware, confidence-aware, and source-backed.
8	 * - Separate ownership, policies, processes, decisions, gotchas, definitions, and facts.
9	 * - Generate imperative agent rules only from high-confidence operational units.
10	 */
11	
12	// ── Sector keyword map (offline, no LLM required) ─────────────────────────────
13	const SECTOR_KEYWORDS: Record<string, string[]> = {
14	  HR: ["hire", "onboard", "employee", "leave", "vacation", "headcount", "people", "payroll", "benefit", "hr", "recruit", "termination"],
15	  Legal: ["compliance", "contract", "legal", "liability", "regulation", "gdpr", "privacy", "terms", "law", "audit", "ip", "copyright"],
16	  Finance: ["budget", "invoice", "payment", "refund", "stripe", "billing", "expense", "revenue", "arr", "finance", "cost", "pricing", "price", "payout"],
17	  Engineering: ["deploy", "server", "api", "code", "bug", "repository", "database", "infrastructure", "endpoint", "vllm", "docker", "gpu", "hip", "service", "migration", "deprecat", "backend", "frontend", "port", "runbook"],
18	  Product: ["feature", "roadmap", "launch", "customer", "feedback", "product", "release", "v1", "v2", "sprint", "backlog", "ux", "design", "prototype"],
19	  "Supply Chain": ["supplier", "inventory", "warehouse", "shipping", "logistics", "stock", "vendor", "procurement", "fulfillment"],
20	};
21	
22	const KIND_ORDER: UnitKind[] = ["ownership", "definition", "policy", "process", "decision", "gotcha", "fact"];
23	
24	const KIND_LABELS: Record<UnitKind, string> = {
25	  ownership: "Ownership",
26	  definition: "Definitions",
27	  policy: "Policies",
28	  process: "Processes",
29	  decision: "Decisions",
30	  gotcha: "Gotchas",
31	  fact: "Facts",
32	};
33	
34	const OPERATIONAL_KIND_ORDER: UnitKind[] = ["definition", "fact"];
35	const MIN_SKILL_CONFIDENCE = 0.5;
36	
37	const DEPARTMENT_RELEVANCE_KEYWORDS: Record<Department, string[]> = {
38	  engineering: ["api", "backend", "billing-svc", "deploy", "endpoint", "frontend", "incident", "infra", "on-call", "pipeline", "runbook", "service", "svc", "vllm"],
39	  product: ["backlog", "feature", "launch", "product", "roadmap", "sprint", "ux"],
40	  legal: ["approval", "compliance", "contract", "legal", "privacy", "terms"],
41	  finance: ["billing", "budget", "discount", "finance", "invoice", "payment", "pricing", "refund", "revenue", "stripe"],
42	  hr: ["benefit", "employee", "headcount", "hire", "hr", "onboard", "payroll", "recruit"],
43	  sales: ["account", "acv", "ae", "arr", "commission", "deal", "deal desk", "discount", "enterprise", "quota", "sales", "salesforce", "smb", "svp", "vp sales"],
44	  marketing: ["campaign", "event", "lead", "marketing", "persona"],
45	  operations: ["approval", "escalation", "operations", "process", "sla", "workflow"],
46	  security: ["access", "auth", "credential", "incident", "policy", "security"],
47	  general: [],
48	};
49	
50	const DEPARTMENT_LABELS: Record<Department, string> = {
51	  engineering: "Engineering",
52	  product: "Product",
53	  legal: "Legal",
54	  finance: "Finance",
55	  hr: "HR",
56	  sales: "Sales",
57	  marketing: "Marketing",
58	  operations: "Operations",
59	  security: "Security",
60	  general: "General",
61	};
62	
63	function normalizeDepartment(value: unknown): Department {
64	  return typeof value === "string" && (DEPARTMENTS as readonly string[]).includes(value)
65	    ? value as Department
66	    : "general";
67	}
68	
69	function sourceIdsForUnit(unit: Unit): string[] {
70	  return Array.from(new Set((unit.evidence ?? []).map((item) => item.sourceId).filter(Boolean) as string[]));
71	}
72	
73	function unitText(unit: Unit): string {
74	  return `${unit.subject} ${unit.statement} ${(unit.entities ?? []).join(" ")}`.toLowerCase();
75	}
76	
77	function departmentAnchorSet(units: Unit[], department: Department): Set<string> {
78	  const anchors = new Set<string>(DEPARTMENT_RELEVANCE_KEYWORDS[department].map((item) => item.toLowerCase()));
79	  for (const unit of units.filter((item) => normalizeDepartment(item.department) === department)) {
80	    anchors.add(subjectFor(unit).toLowerCase());
81	    for (const entity of unit.entities ?? []) anchors.add(entity.toLowerCase());
82	    for (const sourceId of sourceIdsForUnit(unit)) anchors.add(`source:${sourceId}`);
83	  }
84	  return anchors;
85	}
86	
87	function isRelevantGeneralUnit(unit: Unit, department: Department, anchors: Set<string>): boolean {
88	  if (department === "general") return true;
89	  const text = unitText(unit);
90	  for (const sourceId of sourceIdsForUnit(unit)) {
91	    if (anchors.has(`source:${sourceId}`)) return true;
92	  }
93	  for (const anchor of anchors) {
94	    if (anchor.length >= 4 && text.includes(anchor)) return true;
95	  }
96	  return DEPARTMENT_RELEVANCE_KEYWORDS[department].some((keyword) => text.includes(keyword));
97	}
98	
99	function activeUnits(state: State, department?: Department): Unit[] {
100	  const candidates = state.units.filter(
101	    (unit) => !unit.stale && !unit.supersededBy && unit.confidence >= MIN_SKILL_CONFIDENCE,
102	  );
103	  if (!department) return candidates;
104	  const anchors = departmentAnchorSet(candidates, department);
105	  return candidates.filter((unit) => {
106	    const unitDepartment = normalizeDepartment(unit.department);
107	    if (unitDepartment === department) return true;
108	    if (unitDepartment !== "general") return false;
109	    return isRelevantGeneralUnit(unit, department, anchors);
110	  });
111	}
112	
113	function formatDate(value?: string): string {
114	  if (!value) return "unknown";
115	  const date = new Date(value);
116	  return Number.isNaN(date.getTime()) ? value : date.toISOString().slice(0, 10);
117	}
118	
119	function escapeInline(value: string): string {
120	  return value.replace(/\s+/g, " ").trim();
121	}
122	
123	function cleanStatement(unit: Unit): string {
124	  const subject = escapeInline(unit.subject);
125	  let statement = escapeInline(unit.statement);
126	  if (!statement) return "";
127	
128	  if (subject) {
129	    const prefix = new RegExp(`^${subject.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\s+`, "i");
130	    statement = statement.replace(prefix, "");
131	  }
132	  statement = statement.replace(/^the\s+/i, "");
133	  return statement.charAt(0).toUpperCase() + statement.slice(1);
134	}
135	
136	function subjectFor(unit: Unit): string {
137	  return escapeInline(unit.subject || unit.entities?.[0] || "General");
138	}
139	
140	function confidenceRange(units: Unit[]): string {
141	  const values = units.map((unit) => unit.confidence).filter((n) => Number.isFinite(n));
142	  if (values.length === 0) return "unknown";
143	  const min = Math.min(...values).toFixed(2);
144	  const max = Math.max(...values).toFixed(2);
145	  return min === max ? min : `${min}-${max}`;
146	}
147	
148	function aliasesFor(state: State, subject: string): string[] {
149	  const entity = state.entities.find((item) => item.name.toLowerCase() === subject.toLowerCase());
150	  return entity?.aliases?.filter(Boolean) ?? [];
151	}
152	
153	function sourceIdsFor(units: Unit[]): string[] {
154	  const ids = new Set<string>();
155	  for (const unit of units) {
156	    for (const evidence of unit.evidence ?? []) {
157	      if (evidence.sourceId) ids.add(evidence.sourceId);
158	    }
159	  }
160	  return Array.from(ids);
161	}
162	
163	function sourceMapFor(state: State): Map<string, State["sources"][number]> {
164	  return new Map(state.sources.map((source) => [source.id, source]));
165	}
166	
167	function sourceLabel(state: State, sourceId?: string): string {
168	  if (!sourceId) return "unknown";
169	  const source = sourceMapFor(state).get(sourceId);
170	  return source ? `${source.id} (${source.title})` : sourceId;
171	}
172	
173	function relatedEntitiesFor(units: Unit[], subject: string): string[] {
174	  const names = new Set<string>();
175	  for (const unit of units) {
176	    for (const entity of unit.entities ?? []) {
177	      if (entity.toLowerCase() !== subject.toLowerCase()) names.add(entity);
178	    }
179	  }
180	  return Array.from(names).sort((a, b) => a.localeCompare(b));
181	}
182	
183	function latestUpdateFor(units: Unit[]): string {
184	  const timestamps = units
185	    .map((unit) => unit.updatedAt ?? unit.createdAt)
186	    .filter(Boolean)
187	    .map((value) => new Date(value).getTime())
188	    .filter((value) => Number.isFinite(value));
189	  if (timestamps.length === 0) return "unknown";
190	  return new Date(Math.max(...timestamps)).toISOString().slice(0, 10);
191	}
192	
193	function temporalScopeFor(units: Unit[]): string {
194	  const statuses = new Set(units.map((unit) => unit.temporalStatus ?? "unknown"));
195	  if (statuses.size === 1) return Array.from(statuses)[0];
196	  if (statuses.has("future") || statuses.has("historical") || statuses.has("expired")) return "mixed";
197	  return "current";
198	}
199	
200	function domainForUnits(units: Unit[]): string {
201	  const priority: UnitKind[] = ["policy", "process", "ownership", "gotcha", "decision", "definition", "fact"];
202	  for (const kind of priority) {
203	    const subjects = units
204	      .filter((unit) => unit.kind === kind)
205	      .map(subjectFor)
206	      .filter((subject) => subject !== "General");
207	    if (subjects.length > 0) return subjects[0];
208	  }
209	  return "Company Knowledge";
210	}
211	
212	function quoteFor(unit: Unit): string | null {
213	  const quote = unit.evidence?.find((item) => item.quote)?.quote;
214	  return quote ? escapeInline(quote).slice(0, 220) : null;
215	}
216	
217	// Returns the sector for a unit: trusts backend tag if set, else keyword-matches.
218	export function classifySector(unit: Unit): string {
219	  if (unit.sector && unit.sector !== "General") return unit.sector;
220	  const haystack = `${unit.subject} ${unit.statement}`.toLowerCase();
221	  for (const [sector, keywords] of Object.entries(SECTOR_KEYWORDS)) {
222	    if (keywords.some((kw) => haystack.includes(kw))) return sector;
223	  }
224	  return "General";
225	}
226	
227	export function departmentCounts(state: State): Record<Department, number> {
228	  const counts = Object.fromEntries(DEPARTMENTS.map((department) => [department, 0])) as Record<Department, number>;
229	  for (const unit of state.units.filter((item) => !item.stale && !item.supersededBy)) {
230	    counts[normalizeDepartment(unit.department)] += 1;
231	  }
232	  return counts;
233	}
234	
235	function renderStructuredUnit(state: State, unit: Unit): string[] {
236	  const firstSource = sourceIdsForUnit(unit)[0];
237	  const lines = [`- ${subjectFor(unit)}: ${cleanStatement(unit)}`];
238	  lines.push(`  - type: ${unit.kind}`);
239	  lines.push(`  - confidence: ${unit.confidence.toFixed(2)}`);
240	  lines.push(`  - temporal_status: ${unit.temporalStatus ?? "unknown"}`);
241	  lines.push(`  - effective_date: ${unit.effectiveDate ?? "null"}`);
242	  lines.push(`  - valid_from: ${unit.validFrom ?? "null"}`);
243	  lines.push(`  - valid_to: ${unit.validTo ?? "null"}`);
244	  lines.push(`  - updated_at: ${formatDate(unit.updatedAt ?? unit.createdAt)}`);
245	  lines.push(`  - source: ${sourceLabel(state, firstSource)}`);
246	  const quote = quoteFor(unit);
247	  if (quote) lines.push(`  - evidence: "${quote}"`);
248	  else lines.push("  - evidence: null");
249	  return lines;
250	}
251	
252	function renderEntitySection(state: State, subject: string, units: Unit[]): string[] {
253	  const lines: string[] = [`### ${subject}`, ""];
254	  const aliases = aliasesFor(state, subject);
255	  const related = relatedEntitiesFor(units, subject);
256	  const sources = sourceIdsFor(units);
257	
258	  lines.push("metadata:");
259	  lines.push(`  department: ${normalizeDepartment(units[0]?.department)}`);
260	  lines.push(`  sector: ${classifySector(units[0])}`);
261	  lines.push(`  aliases: ${aliases.length ? aliases.join(", ") : "none"}`);
262	  lines.push(`  related_entities: ${related.length ? related.join(", ") : "none"}`);
263	  lines.push(`  source_ids: ${sources.length ? sources.join(", ") : "unknown"}`);
264	  lines.push(`  confidence: ${confidenceRange(units)}`);
265	  lines.push(`  updated_at: ${latestUpdateFor(units)}`);
266	  const temporalStatuses = Array.from(new Set(units.map((unit) => unit.temporalStatus ?? "unknown")));
267	  lines.push(`  temporal_statuses: ${temporalStatuses.join(", ")}`);
268	  lines.push("");
269	
270	  for (const kind of KIND_ORDER) {
271	    const byKind = units.filter((unit) => unit.kind === kind);
272	    if (byKind.length === 0) continue;
273	    lines.push(`#### ${KIND_LABELS[kind]}`);
274	    for (const unit of byKind) lines.push(...renderStructuredUnit(state, unit));
275	    lines.push("");
276	  }
277	
278	  return lines;
279	}
280	
281	function renderGroupedUnits(state: State, heading: string, units: Unit[]): string[] {
282	  if (units.length === 0) return [];
283	  const lines = [`## ${heading}`, ""];
284	  const bySubject = new Map<string, Unit[]>();
285	  for (const unit of units) {
286	    const subject = subjectFor(unit);
287	    const bucket = bySubject.get(subject) ?? [];
288	    bucket.push(unit);
289	    bySubject.set(subject, bucket);
290	  }
291	
292	  for (const [subject, subjectUnits] of Array.from(bySubject.entries()).sort(([a], [b]) => a.localeCompare(b))) {
293	    lines.push(`### ${subject}`, "");
294	    for (const unit of subjectUnits.sort((a, b) => b.confidence - a.confidence)) {
295	      lines.push(...renderStructuredUnit(state, unit), "");
296	    }
297	  }
298	  return lines;
299	}
300	
301	function renderCurrentOperationalFacts(state: State, units: Unit[]): string[] {
302	  const facts = units.filter((unit) => OPERATIONAL_KIND_ORDER.includes(unit.kind));
303	  return renderGroupedUnits(state, "Current Operational Facts", facts);
304	}
305	
306	function renderTemporalNotes(state: State, units: Unit[]): string[] {
307	  const temporalUnits = units.filter((unit) =>
308	    Boolean(unit.validTo || unit.supersededAt || unit.pendingSupersedes?.length)
309	    || ["future", "historical", "expired"].includes(unit.temporalStatus ?? ""),
310	  );
311	  if (temporalUnits.length === 0) return [];
312	
313	  const lines = ["## Temporal Notes", ""];
314	  for (const unit of temporalUnits.sort((a, b) => subjectFor(a).localeCompare(subjectFor(b)))) {
315	    const firstSource = sourceIdsForUnit(unit)[0];
316	    lines.push(`- ${subjectFor(unit)}: ${cleanStatement(unit)}`);
317	    lines.push(`  - current_state: ${unit.temporalStatus === "current" ? cleanStatement(unit) : "not current or unknown"}`);
318	    lines.push(`  - future_or_historical_state: ${unit.temporalStatus ?? "unknown"}`);
319	    lines.push(`  - effective_date: ${unit.effectiveDate ?? "null"}`);
320	    lines.push(`  - valid_from: ${unit.validFrom ?? "null"}`);
321	    lines.push(`  - valid_to: ${unit.validTo ?? "null"}`);
322	    lines.push(`  - superseded_at: ${unit.supersededAt ?? "null"}`);
323	    lines.push(`  - confidence: ${unit.confidence.toFixed(2)}`);
324	    lines.push(`  - source: ${sourceLabel(state, firstSource)}`);
325	  }
326	  lines.push("");
327	  return lines;
328	}
329	
330	function agentRuleFor(unit: Unit): string | null {
331	  const statement = cleanStatement(unit);
332	  if (!statement || unit.confidence < 0.75) return null;
333	  if (unit.temporalStatus && ["expired", "historical"].includes(unit.temporalStatus)) return null;
334	
335	  if (unit.kind === "policy") return `- Policy constraint: ${subjectFor(unit)} - ${statement}`;
336	  if (unit.kind === "process") return `- Follow process: ${subjectFor(unit)} - ${statement}`;
337	  if (unit.kind === "gotcha") return `- Check before acting: ${subjectFor(unit)} - ${statement}`;
338	  if (unit.kind === "ownership") return `- Route ownership questions for ${subjectFor(unit)} using this fact: ${statement}`;
339	  if (unit.kind === "decision") return `- Respect decision context for ${subjectFor(unit)}: ${statement}`;
340	  return null;
341	}
342	
343	function renderAgentRules(units: Unit[]): string[] {
344	  const rules = Array.from(new Set(units.map(agentRuleFor).filter(Boolean) as string[])).slice(0, 30);
345	  const lines = ["## Agent Rules", ""];
346	  lines.push("- Use this skill as company-specific operational memory, not as general advice.");
347	  lines.push("- Prefer current facts over future, historical, expired, or unknown temporal facts.");
348	  lines.push("- Do not treat future effective dates as active before the effective date.");
349	  lines.push("- Do not invent owners, approvals, systems, dates, prices, customers, or incident causes.");
350	  lines.push("- If evidence is missing or confidence is low, say the brain does not have enough information.");
351	  if (rules.length > 0) lines.push(...rules);
352	  lines.push("");
353	  return lines;
354	}
355	
356	function renderWhenToUse(department: Department | undefined, units: Unit[]): string[] {
357	  const kinds = new Set(units.map((unit) => unit.kind));
358	  const subjects = Array.from(new Set(units.map(subjectFor).filter((subject) => subject !== "General"))).slice(0, 8);
359	  const label = department ? DEPARTMENT_LABELS[department] : "company";
360	  const lines = ["## When To Use", "", "Use this skill when an agent needs to:"];
361	  lines.push(`- answer ${label.toLowerCase()} questions using BrainOS evidence`);
362	  if (subjects.length > 0) lines.push(`- reason about ${subjects.join(", ")}`);
363	  if (kinds.has("ownership")) lines.push("- route ownership, approval, escalation, or contact decisions");
364	  if (kinds.has("policy")) lines.push("- apply company policies as constraints before taking action");
365	  if (kinds.has("process")) lines.push("- follow operational workflows from source-backed process facts");
366	  if (kinds.has("gotcha")) lines.push("- avoid known operational gotchas before changing systems or processes");
367	  lines.push("");
368	  lines.push("Do not use this skill for:");
369	  lines.push("- facts outside the listed department/domain scope");
370	  lines.push("- claims not supported by a listed source or evidence quote");
371	  lines.push("- treating historical, expired, or future facts as current");
372	  lines.push("");
373	  return lines;
374	}
375	
376	function renderScope(state: State, department: Department | undefined, units: Unit[]): string[] {
377	  const deptLabel = department ? DEPARTMENT_LABELS[department] : "All departments";
378	  const subjects = Array.from(new Set(units.map(subjectFor).filter(Boolean))).slice(0, 16);
379	  const lines = ["## Scope", ""];
380	  lines.push(`- department: ${department ?? "all"}`);
381	  lines.push(`- domain: ${domainForUnits(units)}`);
382	  lines.push("- applies_to:");
383	  for (const subject of subjects.length ? subjects : ["General"]) lines.push(`  - ${subject}`);
384	  lines.push(`- temporal_scope: ${temporalScopeFor(units)}`);
385	  lines.push(`- generated_at: ${new Date().toISOString()}`);
386	  lines.push(`- source_count: ${sourceIdsFor(units).length || state.sources.length}`);
387	  lines.push(`- label: ${deptLabel}`);
388	  lines.push("");
389	  return lines;
390	}
391	
392	function renderSourceIndex(state: State, units: Unit[]): string[] {
393	  const ids = sourceIdsFor(units);
394	  if (ids.length === 0) return [];
395	  const sources = sourceMapFor(state);
396	  const lines = ["## Source Index", ""];
397	  for (const id of ids.sort()) {
398	    const source = sources.get(id);
399	    if (!source) {
400	      lines.push(`- ${id}: unknown`);
401	      continue;
402	    }
403	    lines.push(`- ${source.id}: ${source.title}, ${formatDate(source.capturedAt)}, ${source.kind}`);
404	  }
405	  lines.push("");
406	  return lines;
407	}
408	
409	function renderRelationships(state: State, units: Unit[]): string[] {
410	  const unitIds = new Set(units.map((unit) => unit.id));
411	  const relationships = (state.relationships ?? []).filter(
412	    (rel) => !rel.unitId || unitIds.has(rel.unitId),
413	  );
414	  if (relationships.length === 0) return [];
415	
416	  const lines = ["## Knowledge Graph Relationships", ""];
417	  for (const rel of relationships.slice(0, 120)) {
418	    const metadata = [
419	      rel.id ? `id:${rel.id}` : "",
420	      rel.sourceId ? `source:${rel.sourceId}` : "",
421	      `confidence:${rel.confidence.toFixed(2)}`,
422	    ].filter(Boolean).join(" | ");
423	    lines.push(`- ${rel.from} --${rel.relation}--> ${rel.to} <!-- ${metadata} -->`);
424	  }
425	  lines.push("");
426	  return lines;
427	}
428	
429	// Render the Code Map section. Only emitted if at least one code source has
430	// been ingested. Stays terse so it doesn't crowd out the operational facts.
431	function renderCodeMap(state: State): string[] {
432	  const codeSources = state.sources.filter((s) => s.kind === "code" && s.codebase);
433	  if (codeSources.length === 0) return [];
434	
435	  const lines: string[] = ["## Code Map", ""];
436	
437	  for (const src of codeSources) {
438	    const cb = src.codebase!;
439	    const langs = Object.entries(cb.byLanguage)
440	      .slice(0, 6)
441	      .map(([k, v]) => `${k}:${v}`)
442	      .join(", ");
443	    const dirs = Object.entries(cb.topLevelDirs)
444	      .slice(0, 8)
445	      .map(([k, v]) => `${k} (${v})`)
446	      .join(", ");
447	
448	    lines.push(`### ${src.title}`);
449	    lines.push(
450	      `- captured: ${src.capturedAt}`,
451	      `- files: ${cb.totalFiles}${cb.truncated ? " (truncated)" : ""}`,
452	      `- languages: ${langs}`,
453	      `- top-level dirs: ${dirs}`,
454	    );
455	    if (cb.rationaleFilesExtracted != null) {
456	      lines.push(`- rationale files extracted: ${cb.rationaleFilesExtracted}`);
457	    }
458	    lines.push("");
459	
460	    // Entity ↔ Path links — the bridge that lets the agent jump from a fact
461	    // (e.g. "billing service was migrated") to the actual code location.
462	    const ep = cb.entityPaths ?? {};
463	    const epEntries = Object.entries(ep).slice(0, 40);
464	    if (epEntries.length > 0) {
465	      lines.push("**Entity → Path**", "");
466	      for (const [entity, paths] of epEntries) {
467	        const shown = paths.slice(0, 4).join(", ") +
468	          (paths.length > 4 ? `, … (+${paths.length - 4} more)` : "");
469	        lines.push(`- \`${entity}\` → ${shown}`);
470	      }
471	      lines.push("");
472	    }
473	
474	    // Module summaries — LLM-generated "what this directory does" overviews.
475	    // Useful as cheap orientation for an agent dropped into an unfamiliar repo.
476	    const modules = cb.moduleSummaries ?? [];
477	    if (modules.length > 0) {
478	      lines.push("**Modules**", "");
479	      for (const m of modules) {
480	        lines.push(`- \`${m.dir}/\` (${m.fileCount} files) — ${m.summary}`);
481	      }
482	      lines.push("");
483	    }
484	
485	    // Top symbols — first ~30 by name. Lets the agent answer "where is X
486	    // defined?" without re-reading code.
487	    const sIndex = cb.symbolIndex ?? {};
488	    const sEntries = Object.entries(sIndex).slice(0, 30);
489	    if (sEntries.length > 0) {
490	      lines.push("**Top symbols → path**", "");
491	      for (const [name, occ] of sEntries) {
492	        const first = occ[0];
493	        const more = occ.length > 1 ? ` (+${occ.length - 1} more defs)` : "";
494	        lines.push(`- \`${name}\` (${first.kind}) — ${first.path}:${first.line}${more}`);
495	      }
496	      lines.push("");
497	    }
498	
499	    // Import-graph hubs — files imported-by many others. Strong "central
500	    // module" signal for the agent.
501	    const ig = cb.importGraph;
502	    if (ig && ig.stats.internalEdges > 0) {
503	      const hubs = ig.stats.hubs.slice(0, 8);
504	      lines.push(
505	        `- import edges: ${ig.stats.internalEdges} internal · ${ig.stats.externalDeps} external deps`,
506	      );
507	      if (hubs.length > 0) {
508	        lines.push("**Import hubs (fan-in)**", "");
509	        for (const h of hubs) {
510	          lines.push(`- ${h.path} ← ${h.fanIn}`);
511	        }
512	        lines.push("");
513	      }
514	    }
515	
516	    // Call-graph top callees — collapses (caller, callee) edges into "this
517	    // function is called N times across the codebase".
518	    const calls = cb.callEdges ?? [];
519	    if (calls.length > 0) {
520	      const counts: Record<string, number> = {};
521	      for (const c of calls) counts[c.callee] = (counts[c.callee] ?? 0) + 1;
522	      const top = Object.entries(counts)
523	        .sort((a, b) => b[1] - a[1])
524	        .slice(0, 10);
525	      lines.push("**Top callees**", "");
526	      for (const [name, n] of top) {
527	        lines.push(`- \`${name}\` — ${n}×`);
528	      }
529	      lines.push("");
530	    }
531	  }
532	
533	  return lines;
534	}
535	
536	export function generateSkills(state: State, department?: Department): string {
537	  const units = activeUnits(state, department);
538	  if (units.length === 0) return "# Skill: Company Knowledge Memory\n\nNo knowledge ingested yet.\n";
539	
540	  const scope = department
541	    ? `${DEPARTMENT_LABELS[department]}${department === "general" ? "" : " + General"}`
542	    : "All departments";
543	  const title = department
544	    ? `# Skill: ${DEPARTMENT_LABELS[department]} ${domainForUnits(units)} Memory`
545	    : "# Skill: Company Knowledge Memory";
546	
547	  const lines: string[] = [
548	    title,
549	    "",
550	    "Generated by BrainOS as compact, source-backed operational memory for agents.",
551	    "",
552	    "metadata:",
553	    "  skill_version: 4",
554	    `  generated_at: ${new Date().toISOString()}`,
555	    `  scope: ${scope}`,
556	    `  retrieval_mode: hybrid_bm25_vector_graph`,
557	    `  units: ${units.length}`,
558	    `  entities: ${state.entities.length}`,
559	    `  sources: ${state.sources.length}`,
560	    `  temporal_scope: ${temporalScopeFor(units)}`,
561	    "",
562	  ];
563	
564	  lines.push(...renderScope(state, department, units));
565	  lines.push(...renderWhenToUse(department, units));
566	
567	  const departments = department
568	    ? department === "general"
569	      ? ["general" as Department]
570	      : [department, "general" as Department]
571	    : DEPARTMENTS;
572	
573	  for (const dept of departments) {
574	    const deptUnits = units.filter((unit) => normalizeDepartment(unit.department) === dept);
575	    if (deptUnits.length === 0) continue;
576	
577	    if (!department) lines.push(`# ${DEPARTMENT_LABELS[dept]} Department Skill`, "");
578	    lines.push(...renderCurrentOperationalFacts(state, deptUnits));
579	    lines.push(...renderGroupedUnits(state, "Ownership And Routing", deptUnits.filter((unit) => unit.kind === "ownership")));
580	    lines.push(...renderGroupedUnits(state, "Policies", deptUnits.filter((unit) => unit.kind === "policy")));
581	    lines.push(...renderGroupedUnits(state, "Processes", deptUnits.filter((unit) => unit.kind === "process")));
582	    lines.push(...renderGroupedUnits(state, "Gotchas", deptUnits.filter((unit) => unit.kind === "gotcha")));
583	    lines.push(...renderGroupedUnits(state, "Decisions", deptUnits.filter((unit) => unit.kind === "decision")));
584	    lines.push(...renderTemporalNotes(state, deptUnits));
585	  }
586	
587	  lines.push(...renderAgentRules(units));
588	  lines.push(...renderRelationships(state, units));
589	  lines.push(...renderCodeMap(state));
590	  lines.push(...renderSourceIndex(state, units));
591	  return lines.join("\n").trimEnd() + "\n";
592	}
593	
594	export function generateSkillsJSON(state: State, department?: Department) {
595	  const units = activeUnits(state, department);
596	  return {
597	    version: 4,
598	    generatedAt: new Date().toISOString(),
599	    department: department ?? "all",
600	    retrievalMode: "hybrid_bm25_vector_graph",
601	    temporalScope: temporalScopeFor(units),
602	    totalUnits: units.length,
603	    totalEntities: state.entities.length,
604	    totalSources: state.sources.length,
605	    scope: {
606	      department: department ?? "all",
607	      domain: units.length ? domainForUnits(units) : "Company Knowledge",
608	      appliesTo: Array.from(new Set(units.map(subjectFor).filter(Boolean))),
609	      temporalScope: temporalScopeFor(units),
610	    },
611	    agentRules: Array.from(new Set(units.map(agentRuleFor).filter(Boolean) as string[])),
612	    units: units.map((unit) => ({
613	      id: unit.id,
614	      kind: unit.kind,
615	      department: normalizeDepartment(unit.department),
616	      sector: classifySector(unit),
617	      subject: unit.subject,
618	      statement: unit.statement,
619	      confidence: unit.confidence,
620	      updatedAt: unit.updatedAt ?? unit.createdAt,
621	      validFrom: unit.validFrom ?? null,
622	      validTo: unit.validTo ?? null,
623	      effectiveDate: unit.effectiveDate ?? null,
624	      observedAt: unit.observedAt ?? null,
625	      supersededAt: unit.supersededAt ?? null,
626	      temporalStatus: unit.temporalStatus ?? "unknown",
627	      entities: unit.entities ?? [],
628	      evidence: unit.evidence ?? [],
629	      sourceIds: sourceIdsForUnit(unit),
630	    })),
631	    relationships: state.relationships ?? [],
632	    entities: state.entities,
633	    sources: state.sources,
634	  };
635	}
